def removeElements(head, val):
    class Node:
        def __init__(self, val=0, next=None):
            self.val = val
            self.next = next
    dummy = Node(-1)
    dummy.next = head
    curr = dummy
    while curr.next:
        if curr.next.val == val:
            curr.next = curr.next.next
        else:
            curr = curr.next
    return dummy.next

